import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as t,e as r}from"./app-706bfe03.js";const i={},s=r('<h1 id="图形渲染管线-graphics-pipeline" tabindex="-1"><a class="header-anchor" href="#图形渲染管线-graphics-pipeline" aria-hidden="true">#</a> 图形渲染管线 ( Graphics Pipeline )</h1><p>图形渲染管线是指一系列操作，它们将空间中的顶点描述的模型转换成二维平面中的图像。</p><p>总的来说，图形渲染管线主要有三步：顶点操作 ( 模型变换 )、光栅化、着色。</p><img class="img-mid" src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/e6c9d24egy1h3qoob0wi2j210q0ok41o.jpg" alt="image-20220630232010469" style="zoom:50%;max-width:1100px;"><p>上图就是图形渲染管线的过程。三维空间中的顶点经空间变换后投影到屏幕空间，然后将顶点连成的三角形进行光栅化，然后对光栅化得到的像素点进行着色。</p><p>以上这些算法操作都已经在硬件层面写好，由显卡中的 GPU 执行。</p><p><em>( 图形管线可以有不同的分法，不一定是上图表示的 5 步，但整体流程是一样的 )</em></p><h2 id="顶点处理" tabindex="-1"><a class="header-anchor" href="#顶点处理" aria-hidden="true">#</a> 顶点处理</h2><img class="img-mid" src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/e6c9d24egy1h3qoocg12hj211g0mstal.jpg" alt="image-20220630232102496" style="zoom:50%;max-width:1100px;"><p>顶点处理是指对所有顶点进行 MVP 变换，最终得到投影到二维平面的坐标信息。超出观察空间的内容会被剪裁掉。</p><p>在一开始定义顶点时，也会定义哪些顶点构成三角形，第二步的三角形处理就是将这些顶点按定义连成三角形交给光栅化处理。</p><h2 id="光栅化" tabindex="-1"><a class="header-anchor" href="#光栅化" aria-hidden="true">#</a> 光栅化</h2><img class="img-mid" src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/e6c9d24egy1h3qoobm4nrj20za0mimzv.jpg" alt="image-20220630232146945" style="zoom:50%;max-width:1100px;"><img class="img-mid" src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/e6c9d24egy1h3qoo8evp5j20z60mowgk.jpg" alt="image-20220630232218715" style="zoom:50%;max-width:1100px;"><h2 id="着色" tabindex="-1"><a class="header-anchor" href="#着色" aria-hidden="true">#</a> 着色</h2><img class="img-mid" src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/e6c9d24egy1h3qooams3nj20y60mugns.jpg" alt="image-20220630232248540" style="zoom:50%;max-width:1100px;"><img class="img-mid" src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/e6c9d24egy1h3qoo9obb0j20zw0mmjul.jpg" alt="image-20220630232343311" style="zoom:50%;max-width:1100px;"><h2 id="可编程渲染管线" tabindex="-1"><a class="header-anchor" href="#可编程渲染管线" aria-hidden="true">#</a> 可编程渲染管线</h2><h3 id="shader-program" tabindex="-1"><a class="header-anchor" href="#shader-program" aria-hidden="true">#</a> shader program</h3>',19),m=[s];function h(c,o){return a(),t("div",null,m)}const n=e(i,[["render",h],["__file","3.4图形渲染管线.html.vue"]]);export{n as default};
